#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define N 300005
#define Q 300005
#define K 300005
#define L 14

int n, q, k, a[N], b[N], c[N], d[N], e[N], f[N], g[N], h[N], i[N], j[N], l[N], r[N], x, y, z, ans[N];

int min(int a, int b) { return a < b ? a : b; }

int max(int a, int b) { return a > b ? a : b; }

void update(int i, int v) {
  for (; i <= n; i += i & -i) {
    ans[i] = min(ans[i], v);
  }
}

int query(int i) {
  int res = 1e9;
  for (; i; i -= i & -i) {
    res = min(res, ans[i]);
  }
  return res;
}

int main() {
  int i, j, k, l, r, x, y, z, t;
  scanf("%d %d %d", &n, &q, &k);
  for (i = 1; i <= n; i++) {
    scanf("%d %d %d %d", &a[i], &b[i], &l[i], &r[i]);
    c[i] = b[i];
    d[i] = l[i];
    e[i] = r[i];
  }
  for (i = 1; i <= n; i++) {
    for (j = 1; j <= k; j++) {
      if (c[i] == j) {
        f[i] = max(f[i - 1], d[i]);
        g[i] = max(g[i - 1], e[i]);
      } else {
        f[i] = max(f[i - 1], d[i]);
        g[i] = max(g[i - 1], e[i]);
      }
    }
  }
  for (i = 1; i <= n; i++) {
    h[i] = max(h[i - 1], f[i]);
    i[i] = max(i[i - 1], g[i]);
  }
  for (i = 1; i <= q; i++) {
    scanf("%d %d", &x, &y);
    z = 1e9;
    for (j = 1; j <= k; j++) {
      if (c[j] == j) {
        if (h[j] <= x && x <= i[j]) {
          z = min(z, abs(x - a[j]));
        }
      } else {
        if (h[j] <= x && x <= i[j]) {
          z = min(z, abs(x - a[j]));
        }
      }
    }
    if (z == 1e9) {
      printf("-1\n");
    } else {
      printf("%d\n", z);
    }
  }
  return 0;
}

